sql:
SELECT COUNT(*) AS sample_count
FROM clay_samples
WHERE location = '1';

SELECT type_name
FROM clay_types
WHERE created_at >= '2023-05-01';

SELECT clay_number
FROM clay_samples
WHERE type_of_clay = '1';

SELECT type_name
FROM clay_types
WHERE type_id = 1;

